import os
import logging
import shutil

# Set up logging configuration
logging.basicConfig(filename='file_deletion.log', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def is_large_file(file_path):
    """Check if a file is larger than 1 MB."""
    return os.path.getsize(file_path) > 1 * 1024 * 1024

def contains_temp_string(file_name):
    """Check if a file name contains 'temp' (case-insensitive)."""
    return 'temp' in file_name.lower()

def delete_large_temp_files(directory):
    """Recursively delete files larger than 1 MB and containing 'temp' in their names."""
    try:
        for root, dirs, files in os.walk(directory):
            for file in files:
                file_path = os.path.join(root, file)
                if is_large_file(file_path) or contains_temp_string(file):
                    try:
                        os.remove(file_path)
                        logging.info(f"Deleted file: {file_path}")
                    except Exception as e:
                        logging.error(f"Error deleting file: {file_path}. Error: {e}")
    except Exception as e:
        logging.error(f"Error processing directory: {directory}. Error: {e}")

